#include <bits/stdc++.h>
using namespace std;

const int N=2e5+10;

int n,m,c[N],d[N],ans;
char s[N],t[N];

void add(int x,int k){
    for(;x<N;x+=(x&(-x)))
        c[x]=min(c[x],k);
}

int ask(int x){
    int res=1e9;
    for(;x;x-=(x&(-x)))
        res=min(res,c[x]);
    return res;
}

int main(){
    scanf("%s",s+1);
    m=strlen(s+1);
    t[0]='$';
    for(int i=1;i<=m;i++){
        t[++n]=s[i];
        if(i<m) t[++n]='#';
    }
    t[n+1]='?';
    memset(c,0x3f,sizeof(c));
    int l=1,r=0;
    for(int i=1;i<=n;i++){
        if(i>r) d[i]=1;
        else d[i]=min(r-i+1,d[l+r-i]);
        while(t[i-d[i]]==t[i+d[i]]) d[i]++;
        if(i+d[i]-1>r) l=i-d[i]+1,r=i+d[i]-1;
    }
    for(int i=1;i<=n;i++){
        if(t[i-d[i]+1]=='#') d[i]--;
        ans=max(ans,i-ask(N-i+d[i]));
        add(N-i-d[i],i);
    }
    printf("%d",ans);
    return 0;
}
